export const getCategoryById = (id) =>
  INVESTMENT_CATEGORIES.find((c) => c.id === id) ?? null;

export const getInstrumentById = (id) =>
  INVESTMENT_INSTRUMENTS.find((i) => i.id === id) ?? null;

export const getInstrumentsByCategory = (categoryId) =>
  INVESTMENT_INSTRUMENTS.filter((i) => i.category === categoryId);

export const getInstrumentsByRegion = (regionCode) =>
  regionCode === "all"
    ? INVESTMENT_INSTRUMENTS
    : INVESTMENT_INSTRUMENTS.filter((i) => i.region === regionCode);

