// Merge static catalog with admin overrides from platform_settings
// overrides shape: { [instrumentId]: { price?, change24h?, changePct24h?, enabled?, ... } }
export const mergeWithOverrides = (overrides = {}) => {
  const base = [...INVESTMENT_INSTRUMENTS];

  // Apply per-instrument overrides
  const merged = base.map((inst) => {
    const ov = overrides[inst.id];
    if (!ov) return inst;
    return { ...inst, ...ov };
  });

  // Append any admin-added custom instruments
  const custom = overrides.__custom ?? [];
  return [...merged, ...custom];
};
